(function() {
  'use strict';

  const SKIP_SELECTORS = [
    '.ytp-skip-ad-button',
    '.ytp-ad-skip-button',
    '.ytp-ad-skip-button-modern',
    '.ytp-ad-skip-button.ytp-button',
    'button.ytp-ad-skip-button',
    '.ytp-ad-skip-button-container button',
    '.ytp-ad-skip-button-slot button',
    '.videoAdUiSkipButton'
  ];

  const OVERLAY_SELECTORS = [
    '.ytp-ad-overlay-close-button',
    '.ytp-ad-overlay-close-container',
    '.iv-close-button'
  ];

  const BANNER_SELECTORS = [
    'ytd-ad-slot-renderer',
    'ytd-banner-promo-renderer',
    'ytd-statement-banner-renderer',
    'ytd-in-feed-ad-layout-renderer',
    'ytd-display-ad-renderer',
    'ytd-promoted-sparkles-web-renderer',
    'ytd-promoted-video-renderer',
    '#masthead-ad',
    'tp-yt-paper-dialog:has(#dismiss-button)',
    '.ytd-mealbar-promo-renderer'
  ];

  function clickElement(selectors) {
    for (const sel of selectors) {
      const el = document.querySelector(sel);
      if (el instanceof HTMLElement) {
        el.click();
        return true;
      }
    }
    return false;
  }

  function removeBannerAds() {
    for (const sel of BANNER_SELECTORS) {
      const els = document.querySelectorAll(sel);
      els.forEach(function(el) {
        el.remove();
      });
    }
  }

  function handleVideoAd() {
    const player = document.querySelector('.html5-video-player');
    if (!player) return;

    const isAdPlaying = player.classList.contains('ad-showing') ||
                        player.classList.contains('ad-interrupting');
    if (!isAdPlaying) return;

    if (clickElement(SKIP_SELECTORS)) return;

    const video = document.querySelector('video.html5-main-video');
    if (video instanceof HTMLVideoElement && video.duration > 0) {
      video.playbackRate = 16;
      video.currentTime = video.duration - 0.1;
      video.muted = true;
    }
  }

  function run() {
    handleVideoAd();
    clickElement(OVERLAY_SELECTORS);
    removeBannerAds();
  }

  run();

  const observer = new MutationObserver(function() {
    run();
  });

  observer.observe(document.body, {
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ['class']
  });

  setInterval(run, 500);

  console.log('[Auto Skip YouTube Ads] Active — ads will be skipped automatically.');
})();
